  `detalii_sport` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `face_sport` enum('DA','NU') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `keycloak_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `locatie_preferata_id` bigint DEFAULT NULL,
  `oras_preferat` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `terapeut_keycloak_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `updated_at` datetime(6) NOT NULL,
  `created_by` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT 'SYSTEM',
  `last_modified_by` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT 'SYSTEM',
